        config.resume = 'AUTO';
      }
    } else if (arg.startsWith('--resume=')) {
      config.resume = arg.substring('--resume='.length);
    } else if (arg === '--session-id' && args[i + 1]) {
      config.sessionId = args[i + 1];
      i++;
