  if (!diff.trim()) {
    console.log('没有检测到任何代码变更。');
    return;
  }

  parsed.prompt = buildReviewPrompt(isAdversarial, diff);

  console.log('提交代码审查请求到 Trae Agent...');

  try {
    const result = await executor.execute(parsed);

    if (parsed.jsonOutput && result.jsonOutput) {
