    return;
  }

  console.log(`通过 ACP 流式执行任务: ${prompt.substring(0, 50)}...`);
  console.log('--- 流式输出 ---\n');

  try {
    await client.initialize({ name: 'trae-plugin-cc', version: '1.0.0' });

    const cwd = process.cwd();
    if (!client.getSessionId()) {
      await client.createSession(cwd, []);
    }

